quickstart:
Install: `npm install --save-dev @gravity-ui/app-layout`

Basic usage with Express:
```js
import express from 'express';
import {createRenderFunction} from '@gravity-ui/app-layout';

const app = express();
const renderLayout = createRenderFunction();

app.get('/', function (req, res) {
  res.send(
    renderLayout({
      title: 'Home page',
      bodyContent: { root: 'Hello world!' },
    }),
  );
});

app.listen(3000);
```

With plugins:
```js
import {createRenderFunction, createDefaultPlugins} from '@gravity-ui/app-layout';

const renderLayout = createRenderFunction(
  createDefaultPlugins({layout: {manifest: 'path/to/assets-manifest.json'}})
);
```

Alternative streaming usage with `generateRenderContent`, `renderHeadContent`, `renderBodyContent` for HTML streaming responses.
